a = 0;  
b = 2;  
n = 4;  
f = @(x) cosh(x);  
h = (b-a)/n;  
x = linspace(a, b, n+1);  
approx_integral = h/2 * (f(x(1)) + 2*sum(f(x(2:end-1))) + f(x(end)));  
fprintf(‘Approximate integral of cosh(x) from 0 to 2 using %d subintervals: %f\n’, n, approx_integral);  
plot(x, f(x)); xlabel('x'); ylabel('cosh(x)'); title('Graph of cosh(x)');

